+@Internal
+public class HBaseValidator extends ConnectorDescriptorValidator {
+
+	public static final String CONNECTOR_TYPE_VALUE_HBASE = "hbase";
+	public static final String CONNECTOR_VERSION_VALUE_143 = "1.4.3";
